const rerankResults = $input.first().json.results;
const originalChunks = $('Postgres Vector Search').all();

// Map hasil rerank ke chunk original dengan field V12
let rerankedChunks = rerankResults.map(result => {
  const original = originalChunks[result.index].json;
  return {
    json: {
      ...original,
      rerank_score: result.relevance_score,
      // Final score: kombinasi hybrid_score + rerank (weighted)
      final_score: (original.hybrid_score || original.similarity || 0) * 0.4
                   + result.relevance_score * 0.6
    }
  };
});

// Urutkan: final_score DESC, lalu doc_year DESC
rerankedChunks.sort((a, b) => {
  const scoreDiff = b.json.final_score - a.json.final_score;
  if (Math.abs(scoreDiff) > 0.005) return scoreDiff;
  return parseInt(b.json.doc_year || 0) - parseInt(a.json.doc_year || 0);
});

// Deteksi konflik: pasal_number sama tapi doc_year berbeda
const pasalMap = {};
const conflicts = [];
for (const chunk of rerankedChunks) {
  const key = `${chunk.json.doc_type}-${chunk.json.pasal_number}`;
  if (pasalMap[key] && pasalMap[key] !== chunk.json.doc_year) {
    conflicts.push({
      pasal: chunk.json.pasal_number,
      doc_type: chunk.json.doc_type,
      years: [pasalMap[key], chunk.json.doc_year]
    });
  } else {
    pasalMap[key] = chunk.json.doc_year;
  }
}

// Tandai chunk dengan conflict flag
rerankedChunks = rerankedChunks.map(chunk => ({
  json: {
    ...chunk.json,
    has_conflict: conflicts.some(c =>
      c.pasal === chunk.json.pasal_number &&
      c.doc_type === chunk.json.doc_type
    ),
    conflicts: conflicts
  }
}));

// Ambil top 6
return rerankedChunks.slice(0, 6);

const chunks = $input.all();
const originalQuery = $('Webhook').first().json.body.query;
const autoDetected = $('Parse Query Intelligence').first().json.auto_detected;

if (chunks.length === 0 || !chunks[0].json.chunk_text) {
  return [{ json: {
    context: 'TIDAK ADA DOKUMEN YANG DITEMUKAN.',
    query: originalQuery,
    sources: [],
    max_rerank_score: 0,
    confidence: 'NONE',
    auto_detected: autoDetected
  }}];
}

const maxScore = chunks[0].json.rerank_score || 0;
const conflicts = chunks[0].json.conflicts || [];

// Hierarki kekuatan hukum
const hierarki = { 'UU': 1, 'PP': 2, 'PMK': 3, 'PER': 4, 'KMK': 5, 'SE': 6 };

// Sort by hierarki hukum untuk tampilan LLM
const sortedChunks = [...chunks].sort((a, b) => {
  const ha = hierarki[a.json.doc_type] || 99;
  const hb = hierarki[b.json.doc_type] || 99;
  if (ha !== hb) return ha - hb;
  return parseInt(b.json.doc_year || 0) - parseInt(a.json.doc_year || 0);
});

const contextParts = sortedChunks.map((item, i) => {
  const d = item.json;
  const hierLabel = hierarki[d.doc_type] ? `[Hierarki ${hierarki[d.doc_type]}]` : '';
  const conflictWarning = d.has_conflict
    ? `PERHATIAN: Ada versi lain dari peraturan ini dengan tahun berbeda.`
    : '';

  // Semantic badges dari V12 metadata
  const semanticBadges = [];
  if (d.contains_definition) semanticBadges.push('Definisi');
  if (d.contains_obligation) semanticBadges.push('Kewajiban');
  if (d.contains_sanction)   semanticBadges.push('Sanksi');
  if (d.contains_procedure)  semanticBadges.push('Prosedur');
  if (d.contains_exception)  semanticBadges.push('Pengecualian');
  if (d.contains_timeline)   semanticBadges.push('Batas Waktu');

  const parts = [
    `--- Sumber ${i+1}: ${d.doc_type} No. ${d.doc_number} Tahun ${d.doc_year} ${hierLabel} ---`,
    `Judul: ${d.doc_title || '-'}`,
    `Pasal: ${d.pasal_number || 'Ketentuan Umum'}`,
    d.breadcrumb ? `Konteks Hierarki: ${d.breadcrumb}` : null,
    d.primary_domain && d.primary_domain !== 'UMUM' ? `Domain Pajak: ${d.primary_domain}` : null,
    d.hierarchy_level ? `Level: ${d.hierarchy_level}` : null,
    semanticBadges.length > 0 ? `Tipe Konten: ${semanticBadges.join(' | ')}` : null,
    d.chunk_summary ? `Ringkasan: ${d.chunk_summary}` : null,
    conflictWarning || null,
    '',
    d.chunk_text
  ];

  return parts.filter(Boolean).join('\n');
});

const contextText = contextParts.join('\n\n');

// Conflict summary
const conflictSummary = conflicts.length > 0
  ? `\n\nPERINGATAN KONFLIK: Ditemukan ${conflicts.length} kemungkinan konflik antar peraturan. Gunakan peraturan dengan tahun terbaru dan hierarki tertinggi (UU > PP > PMK > PER > KMK > SE).`
  : '';

// Confidence level
let confidence = 'LOW';
if (maxScore >= 0.75) confidence = 'HIGH';
else if (maxScore >= 0.50) confidence = 'MEDIUM';

return [{
  json: {
    query: originalQuery,
    context: contextText + conflictSummary,
    max_rerank_score: maxScore,
    confidence: confidence,
    conflicts: conflicts,
    auto_detected: autoDetected,
    sources: sortedChunks.map(c => ({
      doc_title:        c.json.doc_title,
      doc_type:         c.json.doc_type,
      doc_number:       c.json.doc_number,
      doc_year:         c.json.doc_year,
      pasal_number:     c.json.pasal_number,
      source_url:       c.json.source_url,
      hierarchy_level:  c.json.hierarchy_level,
      primary_domain:   c.json.primary_domain,
      semantic_type:    c.json.semantic_type,
      chunk_summary:    c.json.chunk_summary,
      similarity_score: c.json.similarity,
      hybrid_score:     c.json.hybrid_score,
      rerank_score:     c.json.rerank_score,
      final_score:      c.json.final_score,
      quality_score:    c.json.quality_score,
      retrieval_boost:  c.json.retrieval_boost,
      hierarki:         hierarki[c.json.doc_type] || 99
    }))
  }
}];

const autoDetected = $json.auto_detected || {};
const score = ($json.max_rerank_score * 100).toFixed(1);

return [{
  json: {
    answer: `Maaf, pertanyaan Anda tidak dapat dijawab dengan tingkat kepercayaan yang cukup dari database peraturan yang ada (skor relevansi: ${score}%, minimum: 50%).\n\nKemungkinan penyebab:\n- Peraturan terkait belum diinput ke dalam database\n- Pertanyaan menggunakan terminologi yang berbeda dari redaksi peraturan\n- Topik tidak tercakup dalam peraturan perpajakan yang tersedia\n\nSaran:\n- Coba reformulasikan pertanyaan dengan terminologi hukum pajak formal\n- Konsultasikan langsung dengan Kantor Pelayanan Pajak (KPP) setempat\n- Hubungi DJP di kring pajak 1500200`,
    query: $json.query,
    sources: [],
    confidence: 'NONE',
    rerank_score: $json.max_rerank_score,
    auto_detected: autoDetected
  }
}];

