const llmResponse = $input.first().json;
const originalQuery    = $('Webhook').first().json.body.query;
const userJenisPajak   = $('Webhook').first().json.body.jenis_pajak    || null;
const userDocType      = $('Webhook').first().json.body.doc_type       || null;
const userPrimaryDomain = $('Webhook').first().json.body.primary_domain || null;

let parsed = {};
try {
  const raw = llmResponse.choices[0].message.content;
  const clean = raw.replace(/```json|```/g, '').trim();
  parsed = JSON.parse(clean);
} catch(e) {
  parsed = { jenis_pajak: null, doc_type: null, primary_domain: null, expanded_queries: [originalQuery] };
}


// Tambah helper di awal node
function toNullIfString(val) {
  if (!val || val === 'null' || val === 'undefined' || val === '') return null;
  return val;
}

// Lalu gunakan di semua assignment
const finalJenisPajak    = toNullIfString(userJenisPajak)    || toNullIfString(parsed.jenis_pajak)    || null;
const finalDocType       = toNullIfString(userDocType)       || toNullIfString(parsed.doc_type)       || null;
const finalPrimaryDomain = toNullIfString(userPrimaryDomain) || toNullIfString(parsed.primary_domain) || null;

// Gabungkan query original + expanded untuk multi-embedding
const allQueries = [originalQuery, ...(parsed.expanded_queries || [])].slice(0, 4);

return [{
  json: {
    original_query:  originalQuery,
    all_queries:     allQueries,
    jenis_pajak:     finalJenisPajak,
    doc_type:        finalDocType,
    primary_domain:  finalPrimaryDomain,
    auto_detected: {
      jenis_pajak:      parsed.jenis_pajak,
      doc_type:         parsed.doc_type,
      primary_domain:   parsed.primary_domain,
      expanded_queries: parsed.expanded_queries
    }
  }
}];

// Rata-rata semua embedding vectors dari multi-query
// Ini membuat satu vektor "centroid" yang representatif
const embeddingData = $input.first().json.data;

if (!embeddingData || embeddingData.length === 0) {
  throw new Error('[Merge Multi Embeddings] Tidak ada embedding yang dihasilkan.');
}

const dims = embeddingData[0].embedding.length;
const count = embeddingData.length;

// Hitung rata-rata per dimensi
const avgEmbedding = new Array(dims).fill(0);
for (const item of embeddingData) {
  for (let d = 0; d < dims; d++) {
    avgEmbedding[d] += item.embedding[d] / count;
  }
}

// Normalisasi L2 agar tetap unit vector (penting untuk cosine similarity)
const magnitude = Math.sqrt(avgEmbedding.reduce((sum, v) => sum + v * v, 0));
const normalizedEmbedding = magnitude > 0
  ? avgEmbedding.map(v => v / magnitude)
  : avgEmbedding;

return [{
  json: {
    embedding: normalizedEmbedding,
    query_count: count,
    dims: dims
  }
}];

const autoDetected = $json.auto_detected || {};
const score = ($json.max_rerank_score * 100).toFixed(1);

return [{
  json: {
    answer: `Maaf, pertanyaan Anda tidak dapat dijawab dengan tingkat kepercayaan yang cukup dari database peraturan yang ada Kemungkinan penyebab:\n- Peraturan terkait belum diinput ke dalam database\n- Pertanyaan menggunakan terminologi yang berbeda dari redaksi peraturan\n- Topik tidak tercakup dalam peraturan perpajakan yang tersedia\n\nSaran:\n- Coba reformulasikan pertanyaan dengan terminologi hukum pajak formal\n- Konsultasikan langsung dengan Kantor Pelayanan Pajak (KPP) setempat\n- Hubungi DJP di kring pajak 1500200`,
    query: $json.query,
    sources: [],
    confidence: 'NONE',
    rerank_score: $json.max_rerank_score,
    auto_detected: autoDetected,
    status_reason: 'rejected'        // ← tambahkan ini
  }
}];

